import type * as React from 'react';

import {cn} from '@/lib/utils';

/**
 * A multi-line text input field with auto-sizing and consistent form styling.
 *
 * ### Component Props
 *
 * Accepts all standard `<textarea>` element props (`React.ComponentProps<'textarea'>`).
 *
 * | Prop          | Type      | Default |
 * | :------------ | :-------- | :------ |
 * | _focusRing_   | `boolean` | `true`  |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <Textarea placeholder="Type your message here..." />
 * <Textarea rows={5} disabled />
 * <Textarea focusRing={false} />
 * ```
 *
 * ### Accessibility (WCAG 2.2 AA)
 *
 * @wcag 1.4.3 Contrast (Minimum) — text and border colors use DDS semantic tokens meeting contrast ratios.
 * @wcag 2.1.1 Keyboard — natively focusable `<textarea>` element.
 * @wcag 2.4.7 Focus Visible — focus ring applied via `focus-visible:ring-3`. When `focusRing={false}`,
 *   the cursor position serves as the focus indicator, which is a valid affordance for text inputs per WCAG 2.4.7.
 *   Only suppress the ring when the surrounding container provides an alternative visible focus indicator.
 * @wcag 4.1.2 Name, Role, Value — native `<textarea>` element; accessible name via associated `<label>` or `aria-label`.
 */
function Textarea({
  className,
  ref,
  focusRing = true,
  style,
  ...props
}: React.ComponentProps<'textarea'> & {
  /**
   * When false, suppresses the :focus-visible outline.
   * The cursor position is a valid focus indicator for text inputs (WCAG 2.4.7).
   * Only use when the surrounding container provides an alternative visible focus indicator.
   * @default true
   */
  focusRing?: boolean;
}) {
  return (
    <textarea
      ref={ref}
      data-slot="textarea"
      className={cn(
        'flex field-sizing-content min-h-16 w-full rounded border border-input bg-input-bg px-2.5 py-2 text-base text-foreground transition-[color,box-shadow] ease-default outline-none placeholder:text-muted-foreground focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring disabled:cursor-not-allowed disabled:opacity-50 aria-invalid:border-destructive aria-invalid:ring-3 aria-invalid:ring-destructive-subtle md:text-sm high-contrast:placeholder:text-foreground',
        className
      )}
      style={focusRing ? style : {outline: 'none', ...style}}
      {...props}
    />
  );
}

export {Textarea};
